using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace McpServer;

[McpServerToolType]
public sealed class ApiTools
{
    [McpServerTool(Name = "fetch_external_data"), Description("Fetches data from an external API for the given resource path.")]
    public static async Task<string> FetchExternalData(
        IHttpClientFactory httpClientFactory,
        ILogger<ApiTools> logger,
        [Description("The API resource path to query (e.g. \"users/42\").")] string resourcePath,
        CancellationToken cancellationToken)
    {
        using var client = httpClientFactory.CreateClient("ExternalApi");

        logger.LogInformation("Calling external API: {Path}", resourcePath);

        using var response = await client.GetAsync(resourcePath, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync(cancellationToken);

        // Return pretty-printed JSON so the LLM can read it easily.
        using var doc = JsonDocument.Parse(json);
        return JsonSerializer.Serialize(doc, new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.ComponentModel;
using ModelContextProtocol.Protocol;
using ModelContextProtocol.Server;

namespace McpServer;

[McpServerPromptType]
public sealed class SummarizationPrompts
{
    [McpServerPrompt(Name = "summarize"), Description("Generates a prompt that asks the model to summarize the provided text.")]
    public static IList<PromptMessage> Summarize(
        [Description("The text to summarize.")] string text,
        [Description("Optional desired summary style (e.g. \"bullet-points\", \"one-paragraph\").")] string? style = null)
    {
        var instruction = style is not null
            ? $"Summarize the following text in {style} style. Be concise and capture the key points."
            : "Summarize the following text. Be concise and capture the key points.";

        return
        [
            new()
            {
                Role = Role.User,
                Content = new TextContentBlock { Text = $"{instruction}\n\n{text}" },
            },
        ];
    }
}

